@st.cache_data(ttl=120)
def cargar_todas_las_hojas():
    """Carga todas las hojas en una sola conexión para evitar quota exceeded."""
    resultado = {}
    try:
        cliente = conectar()
        sheet = cliente.open("Sistema Carros")
        nombres_existentes = [ws.title for ws in sheet.worksheets()]
        for nombre, headers in HOJAS_HEADERS.items():
            try:
                if nombre not in nombres_existentes:
                    ws = sheet.add_worksheet(title=nombre, rows=1000, cols=30)
                    if headers: ws.append_row(headers)
                    resultado[nombre] = pd.DataFrame(columns=headers)
                else:
                    ws = sheet.worksheet(nombre)
                    data = ws.get_all_records()
                    resultado[nombre] = pd.DataFrame(data) if data else pd.DataFrame(columns=headers)
            except Exception as e:
                resultado[nombre] = pd.DataFrame(columns=HOJAS_HEADERS.get(nombre,[]))
    except Exception as e:
        st.error(f"Error conectando con Google Sheets: {e}")
        for nombre, headers in HOJAS_HEADERS.items():
            resultado[nombre] = pd.DataFrame(columns=headers)
    return resultado

def cargar_hoja(nombre):
    datos = cargar_todas_las_hojas()
    return datos.get(nombre, pd.DataFrame(columns=HOJAS_HEADERS.get(nombre,[])))

def get_ws(nombre):
    return conectar().open("Sistema Carros").worksheet(nombre)

def invalidar():
    cargar_todas_las_hojas.clear()

def fmt(v):
    try: return f"₡{float(v):,.0f}"
    except: return "₡0"

def fmt_usd(v):
    try: return f"${float(v):,.2f}"
    except: return "$0.00"

def to_crc(monto, moneda, tc):
    try:
        m,t = float(monto), float(tc)
        return m*t if moneda=="USD" and t>0 else m
    except: return 0

def calcular_cuota(monto, tasa_anual, plazo_meses):
    try:
        m,t,p = float(monto), float(tasa_anual)/100/12, int(plazo_meses)
        if t==0: return m/p
        return m*(t*(1+t)**p)/((1+t)**p-1)
    except: return 0

def dias_en_inventario(fecha_entrada):
    try:
        fe = pd.to_datetime(fecha_entrada)
        return (datetime.now()-fe).days
    except: return 0

def calcular_inventario(df_inv, df_gv, df_ven):
    if df_inv.empty: return df_inv
    df = df_inv.copy()
    df["ID"] = df["ID"].astype(str)

    # Costos totales
    if not df_gv.empty and "ID Vehículo" in df_gv.columns:
        g = df_gv.copy()
        g["ID Vehículo"] = g["ID Vehículo"].astype(str)
        g["Monto CRC"] = pd.to_numeric(g["Monto CRC"], errors="coerce").fillna(0)
        # Total por vehículo
        ct = g.groupby("ID Vehículo")["Monto CRC"].sum().reset_index()
        ct.columns = ["ID","Costo Total"]
        df = df.merge(ct, on="ID", how="left")
        # Pagado por Edgardo
        ge = g[g["Pagado Por"].astype(str).str.lower().str.contains("edgardo",na=False)]
        ce = ge.groupby("ID Vehículo")["Monto CRC"].sum().reset_index()
        ce.columns = ["ID","Pagado Edgardo"]
        df = df.merge(ce, on="ID", how="left")
        # Pagado por Socio
        gs = g[g["Pagado Por"].astype(str).str.lower().str.contains("socio",na=False)]
        cs = gs.groupby("ID Vehículo")["Monto CRC"].sum().reset_index()
        cs.columns = ["ID","Pagado Socio"]
        df = df.merge(cs, on="ID", how="left")
    else:
        df["Costo Total"] = 0
        df["Pagado Edgardo"] = 0
        df["Pagado Socio"] = 0

    for c in ["Costo Total","Pagado Edgardo","Pagado Socio"]:
        df[c] = pd.to_numeric(df.get(c,0), errors="coerce").fillna(0)

    # Precio de venta
    if not df_ven.empty and "ID Vehículo" in df_ven.columns:
        v = df_ven.copy()
        v["ID Vehículo"] = v["ID Vehículo"].astype(str)
        v["Precio CRC"] = pd.to_numeric(v["Precio CRC"], errors="coerce").fillna(0)
        vs = v.groupby("ID Vehículo")["Precio CRC"].sum().reset_index()
        vs.columns = ["ID","Precio Venta"]
        df = df.merge(vs, on="ID", how="left")
    else: df["Precio Venta"] = 0
    df["Precio Venta"] = pd.to_numeric(df.get("Precio Venta",0), errors="coerce").fillna(0)

    for c in ["Precio Objetivo (CRC)","% Grupo","% Socio"]:
        if c in df.columns: df[c] = pd.to_numeric(df[c], errors="coerce").fillna(0)

    # Ganancias
    df["Ganancia Est."] = df["Precio Objetivo (CRC)"] - df["Costo Total"]
    mask = df["Estado"].astype(str).str.lower().isin(["vendido","financiado"])
    df["Ganancia Real"] = 0.0
    df.loc[mask,"Ganancia Real"] = df.loc[mask,"Precio Venta"] - df.loc[mask,"Costo Total"]

    # Para carros con socio: ganancia siempre 50/50
    es_socio = df["Tipo Propiedad"].astype(str).str.lower() == "con socio"
    df["Ganancia Edgardo"] = 0.0
    df["Ganancia Socio Real"] = 0.0
    df.loc[es_socio & mask,"Ganancia Edgardo"] = df.loc[es_socio & mask,"Ganancia Real"] * 0.5
    df.loc[es_socio & mask,"Ganancia Socio Real"] = df.loc[es_socio & mask,"Ganancia Real"] * 0.5
    df.loc[~es_socio & mask,"Ganancia Edgardo"] = df.loc[~es_socio & mask,"Ganancia Real"] * df.loc[~es_socio & mask,"% Grupo"]

    # Deuda entre socios por carro (quién pagó más gastos)
    df["Deuda Entre Socios"] = 0.0
    df.loc[es_socio,"Deuda Entre Socios"] = df.loc[es_socio,"Pagado Edgardo"] - df.loc[es_socio,"Pagado Socio"]
    # Positivo = Socio le debe a Edgardo, Negativo = Edgardo le debe al Socio

    # Días en inventario
    if "Fecha Entrada" in df.columns:
        df["Días Inventario"] = df["Fecha Entrada"].apply(dias_en_inventario)
    else:
        df["Días Inventario"] = 0

    return df

# ── FUNCIONES DE CORREO ──
def enviar_informe_email(destinatarios, asunto, cuerpo_html, adjunto_bytes=None, nombre_adjunto=None):
    try:
        msg = MIMEMultipart('alternative')
        msg['Subject'] = asunto
        msg['From'] = EMAIL_REMITENTE
        msg['To'] = ", ".join(destinatarios)
        msg.attach(MIMEText(cuerpo_html, 'html'))
        if adjunto_bytes and nombre_adjunto:
            part = MIMEBase('application', 'octet-stream')
            part.set_payload(adjunto_bytes)
            encoders.encode_base64(part)
            part.add_header('Content-Disposition', f'attachment; filename="{nombre_adjunto}"')
            msg.attach(part)
        with smtplib.SMTP_SSL('smtp.gmail.com', 465) as server:
            server.login(EMAIL_REMITENTE, EMAIL_PASSWORD)
            server.sendmail(EMAIL_REMITENTE, destinatarios, msg.as_string())
        return True
    except Exception as e:
        st.error(f"Error enviando correo: {e}")
        return False

