def generar_link_whatsapp(telefono, mensaje):
    telefono = telefono.replace("-","").replace(" ","").replace("+","")
    if not telefono.startswith("506"): telefono = "506" + telefono
    import urllib.parse
    return f"https://wa.me/{telefono}?text={urllib.parse.quote(mensaje)}"

def link_carro_whatsapp(row):
    nombre = row.get("Vehículo","")
    año = row.get("Año","")
    precio = row.get("Precio Objetivo (CRC)",0)
    placa = row.get("Placa","")
    notas = row.get("Notas","") or ""
    msg = f"🚗 *{nombre} {año}*\n💰 Precio: ₡{float(precio):,.0f}\n🔑 Placa: {placa}\n{notas}\n\n¡Disponible en Gallery Motors by UR! Contáctenos para más información."
    import urllib.parse
    return f"https://wa.me/?text={urllib.parse.quote(msg)}"

